import Alpine from './alpinejs';

document.addEventListener('alpine:init', () => {
    Alpine.data('surveyExecutionPeriodEditable', (itemId, jsonValue) => {
        const parsedValue = JSON.parse(jsonValue);

        return {
            itemId,

            startTime: parsedValue[0],
            endTime: parsedValue[1],

            editing: false,
        };
    });
});
